1015   case Instruction::Or:
1016     computeKnownBits(I->getOperand(1), DemandedElts, Known, Depth + 1, Q);
1017     computeKnownBits(I->getOperand(0), DemandedElts, Known2, Depth + 1, Q);
1018 
1019     Known = getKnownBitsFromAndXorOr(I, DemandedElts, Known2, Known, Depth, Q);
1020     break;
